hooks.command:
node --input-type=module <<'EOF'
import { readFileSync } from 'fs';
const input = JSON.parse(readFileSync('/dev/stdin', 'utf8'));
const cmd = input?.tool_input?.command || '';

// Block git push --force (require --force-with-lease)
if (/git push.*--force(?!-with-lease)/.test(cmd)) {
  process.stderr.write('[git-workflow] Use --force-with-lease instead of --force to avoid overwriting remote commits.\n');
  process.exit(2);
}

// Block direct commits to main/master/develop
if (/git commit/.test(cmd)) {
  const { execSync } = await import('child_process');
  try {
    const branch = execSync('git branch --show-current', { encoding: 'utf8' }).trim();
    if (/^(main|master|develop|staging|production)$/.test(branch)) {
      process.stderr.write(`[git-workflow] You are about to commit directly to '${branch}'. Use a feature branch instead.\nIf this is intentional, run the git command directly in your terminal.\n`);
      process.exit(2);
    }
  } catch { /* not in a git repo, allow */ }
}
EOF
